// components/reports/LabReport/LaboratoryTable.tsx
"use client";

import React from "react";

interface LabValue {
  name: string;
  value: string | number;
  unit?: string;
  reference_range?: string;
  flag?: string;
}

interface LaboratoryTableProps {
  labValues?: LabValue[];
}

export default function LaboratoryTable({ labValues = [] }: LaboratoryTableProps) {
  if (labValues.length === 0) {
    return null;
  }

  const getRowStyle = (flag?: string) => {
    switch (flag) {
      case "H":
        return "bg-amber-50 hover:bg-amber-100";
      case "L":
        return "bg-blue-50 hover:bg-blue-100";
      case "A":
      case "C":
        return "bg-red-50 hover:bg-red-100";
      default:
        return "bg-white hover:bg-gray-50";
    }
  };

  const getStatusBadge = (flag?: string) => {
    switch (flag) {
      case "H":
        return <span className="inline-flex rounded-full border border-amber-300 bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-800">High</span>;
      case "L":
        return <span className="inline-flex rounded-full border border-blue-300 bg-blue-100 px-2 py-0.5 text-xs font-medium text-blue-800">Low</span>;
      case "A":
      case "C":
        return <span className="inline-flex rounded-full border border-red-300 bg-red-100 px-2 py-0.5 text-xs font-medium text-red-800">Critical</span>;
      default:
        return <span className="inline-flex rounded-full border border-emerald-300 bg-emerald-100 px-2 py-0.5 text-xs font-medium text-emerald-800">Normal</span>;
    }
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white shadow-sm overflow-hidden">
      <div className="border-b border-gray-200 bg-gray-50 px-6 py-4">
        <h2 className="text-sm font-bold uppercase tracking-widest text-gray-500">Laboratory Results</h2>
      </div>
      
      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50 sticky top-0">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-bold uppercase tracking-wider text-gray-500">Test</th>
              <th className="px-6 py-3 text-left text-xs font-bold uppercase tracking-wider text-gray-500">Result</th>
              <th className="px-6 py-3 text-left text-xs font-bold uppercase tracking-wider text-gray-500">Unit</th>
              <th className="px-6 py-3 text-left text-xs font-bold uppercase tracking-wider text-gray-500">Reference Range</th>
              <th className="px-6 py-3 text-left text-xs font-bold uppercase tracking-wider text-gray-500">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {labValues.map((lab, index) => (
              <tr key={index} className={`transition-colors ${getRowStyle(lab.flag)}`}>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                  {lab.name}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm">
                  <span className="font-mono font-semibold text-gray-900">{lab.value}</span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                  {lab.unit || "—"}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                  {lab.reference_range || "—"}
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  {getStatusBadge(lab.flag)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
