// components/reports/LabReport/WarningSection.tsx
"use client";

import React from "react";
import { TriangleAlert, Info, AlertOctagon } from "lucide-react";

interface WarningSectionProps {
  warnings?: string[];
}

export default function WarningSection({ warnings = [] }: WarningSectionProps) {
  if (!warnings || warnings.length === 0) {
    return null;
  }

  const getWarningStyle = (warning: string) => {
    const lower = warning.toLowerCase();
    if (lower.includes("critical") || lower.includes("emergency") || lower.includes("danger")) {
      return {
        style: "border-red-200 bg-red-50 text-red-900",
        icon: AlertOctagon,
        label: "Critical"
      };
    }
    if (lower.includes("important") || lower.includes("warning") || lower.includes("caution")) {
      return {
        style: "border-amber-200 bg-amber-50 text-amber-900",
        icon: TriangleAlert,
        label: "Important"
      };
    }
    return {
      style: "border-blue-200 bg-blue-50 text-blue-900",
      icon: Info,
      label: "Educational"
    };
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Warnings</h2>
      <div className="space-y-3">
        {warnings.map((warning, index) => {
          const { style, icon: Icon, label } = getWarningStyle(warning);
          return (
            <div key={index} className={`flex items-start gap-3 rounded-lg border p-4 ${style}`}>
              <Icon className="h-5 w-5 shrink-0 mt-0.5" strokeWidth={2} />
              <div className="flex-1">
                <p className="text-xs font-medium uppercase tracking-wider opacity-75 mb-1">{label}</p>
                <p className="text-sm leading-relaxed">{warning}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
