// components/reports/LabReport/KeyFindings.tsx
"use client";

import React from "react";
import { CheckCircle2, AlertTriangle, XCircle, Activity } from "lucide-react";

interface KeyFindingsProps {
  findings?: string[];
  labValues?: any[];
}

export default function KeyFindings({ findings = [], labValues = [] }: KeyFindingsProps) {
  // Categorize lab values by status
  const normal = labValues.filter((lab) => lab.flag === "N" || !lab.flag);
  const abnormal = labValues.filter((lab) => lab.flag === "H" || lab.flag === "L");
  const critical = labValues.filter((lab) => lab.flag === "A" || lab.flag === "C");

  const allFindings = [
    ...findings.map((f) => ({ text: f, type: "info" as const })),
    ...normal.slice(0, 3).map((lab) => ({ text: `${lab.name}: ${lab.value} ${lab.unit || ""}`, type: "normal" as const })),
    ...abnormal.slice(0, 3).map((lab) => ({ text: `${lab.name}: ${lab.value} ${lab.unit || ""} (${lab.flag})`, type: "abnormal" as const })),
    ...critical.slice(0, 3).map((lab) => ({ text: `${lab.name}: ${lab.value} ${lab.unit || ""} (${lab.flag})`, type: "critical" as const })),
  ];

  if (allFindings.length === 0) {
    return null;
  }

  const getFindingStyle = (type: string) => {
    switch (type) {
      case "normal":
        return "border-emerald-200 bg-emerald-50 text-emerald-900";
      case "abnormal":
        return "border-amber-200 bg-amber-50 text-amber-900";
      case "critical":
        return "border-red-200 bg-red-50 text-red-900";
      default:
        return "border-blue-200 bg-blue-50 text-blue-900";
    }
  };

  const getFindingIcon = (type: string) => {
    switch (type) {
      case "normal":
        return CheckCircle2;
      case "abnormal":
        return AlertTriangle;
      case "critical":
        return XCircle;
      default:
        return Activity;
    }
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Key Findings</h2>
      <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
        {allFindings.map((finding, index) => {
          const Icon = getFindingIcon(finding.type);
          return (
            <div
              key={index}
              className={`flex items-start gap-3 rounded-lg border p-4 ${getFindingStyle(finding.type)}`}
            >
              <Icon className="h-5 w-5 shrink-0 mt-0.5" strokeWidth={2} />
              <div className="flex-1">
                <p className="text-sm font-medium leading-relaxed">{finding.text}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
