// components/reports/LabReport/ConfidenceSection.tsx
"use client";

import React from "react";
import { ShieldCheck } from "lucide-react";

interface ConfidenceSectionProps {
  confidence: number;
  confidenceLevel?: string;
}

export default function ConfidenceSection({ confidence, confidenceLevel }: ConfidenceSectionProps) {
  const percentage = Math.round(confidence * 100);
  
  const getConfidenceColor = (conf: number) => {
    if (conf >= 0.8) return "bg-emerald-500";
    if (conf >= 0.5) return "bg-amber-500";
    return "bg-red-500";
  };

  const getConfidenceLabel = (conf: number) => {
    if (conf >= 0.8) return "High";
    if (conf >= 0.5) return "Medium";
    return "Low";
  };

  const getConfidenceLabelColor = (conf: number) => {
    if (conf >= 0.8) return "text-emerald-700 bg-emerald-50 border-emerald-200";
    if (conf >= 0.5) return "text-amber-700 bg-amber-50 border-amber-200";
    return "text-red-700 bg-red-50 border-red-200";
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-full bg-blue-100 text-blue-600">
            <ShieldCheck className="h-5 w-5" strokeWidth={2} />
          </div>
          <div>
            <h2 className="text-sm font-bold uppercase tracking-widest text-gray-500">Analysis Confidence</h2>
            <p className="text-xs text-gray-400 mt-1">Based on available data and AI analysis</p>
          </div>
        </div>
        
        <div className="text-right">
          <span className={`inline-flex items-center rounded-full border px-3 py-1.5 text-xs font-medium ${getConfidenceLabelColor(confidence)}`}>
            {getConfidenceLabel(confidence)} Confidence
          </span>
          <p className="mt-1 text-2xl font-semibold text-gray-900">{percentage}%</p>
        </div>
      </div>

      <div className="mt-4">
        <div className="h-2 w-full overflow-hidden rounded-full bg-gray-200">
          <div
            className={`h-full rounded-full transition-all duration-500 ${getConfidenceColor(confidence)}`}
            style={{ width: `${percentage}%` }}
            role="progressbar"
            aria-valuenow={percentage}
            aria-valuemin={0}
            aria-valuemax={100}
          />
        </div>
      </div>
    </div>
  );
}
