// components/reports/LabReport/DoctorInterpretation.tsx
"use client";

import React from "react";
import { Stethoscope } from "lucide-react";

interface DoctorInterpretationProps {
  interpretation: string;
}

export default function DoctorInterpretation({ interpretation }: DoctorInterpretationProps) {
  if (!interpretation) {
    return null;
  }

  // Parse the interpretation text to extract paragraphs
  const paragraphs = interpretation.split(/\n\n+/).filter(p => p.trim());

  return (
    <div className="rounded-xl border-l-4 border-blue-500 bg-blue-50 p-6 shadow-sm">
      <div className="flex items-start gap-3">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-blue-100 text-blue-600">
          <Stethoscope className="h-5 w-5" strokeWidth={2} />
        </div>
        <div className="flex-1">
          <h2 className="mb-3 text-sm font-bold uppercase tracking-widest text-blue-900">Doctor Interpretation</h2>
          <div className="space-y-3">
            {paragraphs.map((paragraph, index) => (
              <p key={index} className="text-sm leading-relaxed text-gray-800">
                {paragraph}
              </p>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
