// components/reports/LabReport/PatientInformation.tsx
"use client";

import React from "react";
import { UserRound, Stethoscope, Building2, Calendar, FileText } from "lucide-react";

interface PatientInformationProps {
  patientName?: string;
  age?: string;
  gender?: string;
  physician?: string;
  facility?: string;
  reportDate?: string;
  collectionDate?: string;
  medicalRecordNumber?: string;
}

export default function PatientInformation({
  patientName,
  age,
  gender,
  physician,
  facility,
  reportDate,
  collectionDate,
  medicalRecordNumber,
}: PatientInformationProps) {
  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    try {
      return new Date(dateStr).toLocaleDateString("en-US", {
        year: "numeric",
        month: "short",
        day: "numeric",
      });
    } catch {
      return dateStr;
    }
  };

  const infoCards = [
    { icon: UserRound, label: "Patient", value: patientName || "N/A" },
    { icon: Calendar, label: "Age", value: age || "N/A" },
    { icon: UserRound, label: "Sex", value: gender || "N/A" },
    { icon: Stethoscope, label: "Physician", value: physician || "N/A" },
    { icon: Building2, label: "Facility", value: facility || "N/A" },
    { icon: FileText, label: "Report Date", value: formatDate(reportDate) },
    { icon: Calendar, label: "Collection Date", value: formatDate(collectionDate) },
    { icon: FileText, label: "MRN", value: medicalRecordNumber || "N/A" },
  ];

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Patient Summary</h2>
      <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
        {infoCards.map((card, index) => {
          const Icon = card.icon;
          return (
            <div
              key={index}
              className="rounded-lg border border-gray-100 bg-gray-50 p-3 transition hover:border-gray-200 hover:bg-gray-100"
            >
              <div className="flex items-center gap-2 text-xs font-medium text-gray-500">
                <Icon className="h-3.5 w-3.5" strokeWidth={2} />
                {card.label}
              </div>
              <p className="mt-1 text-sm font-medium text-gray-900">{card.value}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
}
