// components/reports/LabReport/Header.tsx
"use client";

import React from "react";
import { FlaskConical, ShieldCheck, Calendar, FileText } from "lucide-react";

interface HeaderProps {
  title: string;
  documentType: string;
  dateGenerated: string;
  confidence: number;
  processingStatus: string;
  sourceDocument?: string;
}

export default function Header({
  title,
  documentType,
  dateGenerated,
  confidence,
  processingStatus,
  sourceDocument,
}: HeaderProps) {
  const formatDate = (dateStr: string) => {
    try {
      return new Date(dateStr).toLocaleDateString("en-US", {
        year: "numeric",
        month: "long",
        day: "numeric",
      });
    } catch {
      return dateStr;
    }
  };

  const getConfidenceColor = (conf: number) => {
    if (conf >= 0.8) return "bg-emerald-100 text-emerald-700 border-emerald-200";
    if (conf >= 0.5) return "bg-amber-100 text-amber-700 border-amber-200";
    return "bg-red-100 text-red-700 border-red-200";
  };

  const getConfidenceLabel = (conf: number) => {
    if (conf >= 0.8) return "High";
    if (conf >= 0.5) return "Medium";
    return "Low";
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-blue-50 text-blue-600">
              <FlaskConical className="h-6 w-6" strokeWidth={2} />
            </div>
            <div>
              <h1 className="text-2xl font-semibold tracking-tight text-gray-900">{title}</h1>
              <div className="mt-1 flex flex-wrap items-center gap-2">
                <span className="inline-flex items-center rounded-full border border-blue-200 bg-blue-50 px-3 py-1 text-xs font-medium text-blue-700">
                  {documentType}
                </span>
                {sourceDocument && (
                  <span className="flex items-center gap-1 text-xs text-gray-500">
                    <FileText className="h-3 w-3" strokeWidth={2} />
                    {sourceDocument}
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2 text-xs text-gray-500">
            <Calendar className="h-4 w-4" strokeWidth={2} />
            <span>{formatDate(dateGenerated)}</span>
          </div>

          <div className={`inline-flex items-center gap-1.5 rounded-full border px-3 py-1.5 text-xs font-medium ${getConfidenceColor(confidence)}`}>
            <ShieldCheck className="h-3.5 w-3.5" strokeWidth={2} />
            <span>{getConfidenceLabel(confidence)} Confidence</span>
            <span className="ml-1 font-mono">{Math.round(confidence * 100)}%</span>
          </div>

          <span className="inline-flex items-center rounded-full border border-green-200 bg-green-50 px-3 py-1.5 text-xs font-medium text-green-700">
            {processingStatus}
          </span>
        </div>
      </div>
    </div>
  );
}
