// components/reports/LabReport/Recommendations.tsx
"use client";

import React from "react";
import { CheckCircle2 } from "lucide-react";

interface RecommendationsProps {
  recommendations?: any;
}

export default function Recommendations({ recommendations }: RecommendationsProps) {
  if (!recommendations) {
    return null;
  }

  // Flatten all recommendation types into a single list
  const allRecommendations: { text: string; category: string }[] = [];
  
  if (recommendations.foods_to_eat) {
    allRecommendations.push(...recommendations.foods_to_eat.map((r: string) => ({ text: r, category: "Food to Eat" })));
  }
  if (recommendations.foods_to_avoid) {
    allRecommendations.push(...recommendations.foods_to_avoid.map((r: string) => ({ text: r, category: "Food to Avoid" })));
  }
  if (recommendations.drinks_to_have) {
    allRecommendations.push(...recommendations.drinks_to_have.map((r: string) => ({ text: r, category: "Drink to Have" })));
  }
  if (recommendations.drinks_to_avoid) {
    allRecommendations.push(...recommendations.drinks_to_avoid.map((r: string) => ({ text: r, category: "Drink to Avoid" })));
  }
  if (recommendations.exercises_recommended) {
    allRecommendations.push(...recommendations.exercises_recommended.map((r: string) => ({ text: r, category: "Exercise" })));
  }
  if (recommendations.exercises_to_avoid) {
    allRecommendations.push(...recommendations.exercises_to_avoid.map((r: string) => ({ text: r, category: "Exercise to Avoid" })));
  }
  if (recommendations.rest_recommendation) {
    allRecommendations.push({ text: recommendations.rest_recommendation, category: "Rest" });
  }

  if (allRecommendations.length === 0) {
    return null;
  }

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Recommendations</h2>
      <div className="space-y-3">
        {allRecommendations.map((rec, index) => (
          <div key={index} className="flex items-start gap-3 rounded-lg border border-gray-100 bg-gray-50 p-4 transition hover:border-gray-200 hover:bg-gray-100">
            <div className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-emerald-100 text-emerald-600">
              <CheckCircle2 className="h-4 w-4" strokeWidth={2} />
            </div>
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-900">{rec.category}</p>
              <p className="mt-1 text-sm text-gray-700">{rec.text}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
