// components/reports/LabReport/MedicationSection.tsx
"use client";

import React from "react";
import { Pill, AlertCircle } from "lucide-react";

interface Medication {
  name: string;
  dosage?: string;
  frequency?: string;
  route?: string;
  status?: string;
}

interface MedicationSectionProps {
  medications?: Medication[];
}

export default function MedicationSection({ medications = [] }: MedicationSectionProps) {
  if (!medications || medications.length === 0) {
    return (
      <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
        <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Medications</h2>
        <div className="flex flex-col items-center justify-center py-8 text-center">
          <Pill className="h-12 w-12 text-gray-300" strokeWidth={2} />
          <p className="mt-3 text-sm text-gray-500">No medications listed in this report</p>
        </div>
      </div>
    );
  }

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h2 className="mb-4 text-sm font-bold uppercase tracking-widest text-gray-500">Medications</h2>
      <div className="grid gap-4 md:grid-cols-2">
        {medications.map((med, index) => (
          <div key={index} className="rounded-lg border border-gray-200 bg-gray-50 p-4 transition hover:border-gray-300 hover:bg-gray-100">
            <div className="flex items-start gap-3">
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-blue-100 text-blue-600">
                <Pill className="h-5 w-5" strokeWidth={2} />
              </div>
              <div className="flex-1">
                <h3 className="text-base font-semibold text-gray-900">{med.name}</h3>
                <div className="mt-2 space-y-1">
                  {med.dosage && (
                    <p className="text-sm text-gray-600">
                      <span className="font-medium">Dose:</span> {med.dosage}
                    </p>
                  )}
                  {med.frequency && (
                    <p className="text-sm text-gray-600">
                      <span className="font-medium">Frequency:</span> {med.frequency}
                    </p>
                  )}
                  {med.route && (
                    <p className="text-sm text-gray-600">
                      <span className="font-medium">Route:</span> {med.route}
                    </p>
                  )}
                  {med.status && (
                    <p className="text-sm text-gray-600">
                      <span className="font-medium">Status:</span> {med.status}
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
