// components/reports/LabReport/ClinicalImpression.tsx
"use client";

import React from "react";
import { Activity } from "lucide-react";

interface ClinicalImpressionProps {
  impression: string[];
}

export default function ClinicalImpression({ impression = [] }: ClinicalImpressionProps) {
  if (!impression || impression.length === 0) {
    return null;
  }

  return (
    <div className="rounded-xl border border-amber-200 bg-amber-50 p-6 shadow-sm">
      <div className="flex items-start gap-3">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-amber-100 text-amber-600">
          <Activity className="h-5 w-5" strokeWidth={2} />
        </div>
        <div className="flex-1">
          <h2 className="mb-3 text-sm font-bold uppercase tracking-widest text-amber-900">Clinical Impression</h2>
          <div className="space-y-2">
            {impression.map((item, index) => (
              <p key={index} className="text-sm leading-relaxed text-gray-800">
                {item}
              </p>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
