// components/reports/LabReport/LabReportRenderer.tsx
"use client";

import React from "react";
import { UserRound, FlaskConical, Stethoscope, Activity, CheckCircle2, TriangleAlert, BookOpen, ShieldCheck, Calendar, FileText } from "lucide-react";
import Header from "./Header";
import PatientInformation from "./PatientInformation";
import KeyFindings from "./KeyFindings";
import LaboratoryTable from "./LaboratoryTable";
import DoctorInterpretation from "./DoctorInterpretation";
import ClinicalImpression from "./ClinicalImpression";
import Recommendations from "./Recommendations";
import MedicationSection from "./MedicationSection";
import WarningSection from "./WarningSection";
import EvidenceSection from "./EvidenceSection";
import ConfidenceSection from "./ConfidenceSection";
import Disclaimer from "./Disclaimer";

interface LabReportRendererProps {
  data: any; // ChatResponse with unified_context
  unifiedContext?: any; // UnifiedMedicalContext from file upload
}

export default function LabReportRenderer({ data, unifiedContext }: LabReportRendererProps) {
  // Extract patient information from unified_context or data
  const patientInfo = unifiedContext?.patient_information || {};
  const documentInfo = unifiedContext?.document_information || {};
  const labValues = unifiedContext?.lab_values || [];
  const medications = unifiedContext?.medications || [];
  const warnings = unifiedContext?.warnings || [];
  const clinicalFindings = unifiedContext?.clinical_findings || [];
  const confidence = unifiedContext?.confidence_level || unifiedContext?.overall_confidence || 0;
  const confidenceScore = unifiedContext?.confidence_scores?.overall || confidence;

  return (
    <div className="w-full space-y-6 rounded-2xl bg-gray-50 p-6 md:p-8">
      {/* Header */}
      <Header
        title="Clinical Laboratory Report"
        documentType={unifiedContext?.classification || "Laboratory Report"}
        dateGenerated={documentInfo.date || new Date().toISOString()}
        confidence={confidenceScore}
        processingStatus="complete"
        sourceDocument={unifiedContext?.filename || documentInfo.title}
      />

      {/* Patient Information */}
      <PatientInformation
        patientName={patientInfo.name}
        age={patientInfo.age}
        gender={patientInfo.gender}
        physician={unifiedContext?.provider_information?.name}
        facility={unifiedContext?.provider_information?.organization}
        reportDate={documentInfo.date}
        collectionDate={documentInfo.date}
        medicalRecordNumber={patientInfo.patient_id}
      />

      {/* Key Findings */}
      <KeyFindings findings={clinicalFindings} labValues={labValues} />

      {/* Laboratory Results Table */}
      <LaboratoryTable labValues={labValues} />

      {/* Doctor Interpretation */}
      <DoctorInterpretation interpretation={data?.answer || ""} />

      {/* Clinical Impression */}
      <ClinicalImpression impression={data?.suspected_conditions || []} />

      {/* Recommendations */}
      <Recommendations recommendations={data?.recommendations || []} />

      {/* Medication Section */}
      <MedicationSection medications={medications} />

      {/* Warning Section */}
      <WarningSection warnings={warnings} />

      {/* Evidence/Sources */}
      <EvidenceSection sources={data?.sources || []} />

      {/* Confidence */}
      <ConfidenceSection confidence={confidenceScore} confidenceLevel={unifiedContext?.confidence_level} />

      {/* Disclaimer */}
      <Disclaimer />
    </div>
  );
}
